  `release_year_albums` year DEFAULT NULL,
  `genre` varchar(100) DEFAULT NULL,
  `country` varchar(100) DEFAULT NULL,
  `country_code` varchar(10) DEFAULT NULL,
  `streams_albums` bigint DEFAULT '0',
  `weekly_gain_streams_albums` bigint DEFAULT '0',
  `monthly_gain_streams_albums` bigint DEFAULT '0',
  PRIMARY KEY (`album_spotify_id`),
  KEY `artist_spotify_id` (`artist_spotify_id`),
  CONSTRAINT `most_streamed_albums_ibfk_1` FOREIGN KEY (`artist_spotify_id`) REFERENCES `artists` (`artist_spotify_id`) ON DELETE SET NULL ON UPDATE CASCADE
